const readline = require('readline');

function main() {
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });

    let inputLines = [];

    rl.on('line', (line) => {
        inputLines.push(line);
        if (inputLines.length === parseInt(inputLines[0].split(' ')[0]) + 1) {
            rl.close();
        }
    });

    rl.on('close', () => {
        // Extract the number of pairs and the divisor k
        let [n, k] = inputLines[0].split(' ').map(Number);
        let pairs = inputLines.slice(1);

        // Iterate through pairs to find and print those whose sum is divisible by k
        pairs.forEach(pairLine => {
            let [a, b] = pairLine.split(' ').map(Number);
            if ((a + b) % k === 0) {
                console.log(`(${a}, ${b})`);
            }
        });
    });
}

main();
